class Point {
    double x;
    double y;

    Point(double x, double y) {
        this.x = x;
        this.y = y;
    }

    // Default: origin (0, 0)
    Point() {
        this(0, 0);  // calls the two-arg constructor!
    }

    double distanceTo(Point other) {
        double dx = this.x - other.x;
        double dy = this.y - other.y;
        return Math.sqrt(dx*dx + dy*dy);
    }

    @Override
    public String toString() {
        return String.format("(%.1f, %.1f)", x, y);
    }
}

public class Main {
    public static void main(String[] args) {
        Point origin = new Point();
        Point p = new Point(3, 4);

        System.out.println(origin);
        System.out.println(p);
        System.out.printf("Distance: %.1f%n", origin.distanceTo(p));
    }
}

class User {
    String name;
    User(String name) { this.name = name; }
}

public class Main {
    public static void main(String[] args) {
        User u1 = new User("Alex");
        User u2 = u1;  // u2 points to the SAME object

        u2.name = "Jordan";
        System.out.println(u1.name); // Jordan! Same object.

        // NullPointerException if not checked:
        User u3 = null;
        if (u3 != null) {
            System.out.println(u3.name);
        } else {
            System.out.println("u3 is null");
        }
    }
}
